ALTER TABLE ontology_axioms ADD COLUMN IF NOT EXISTS status TEXT;                                   -- active | revising | retired
COMMENT ON TABLE ontology_axioms IS 'Positive-form invariants the project is built on. These are the load-bearing claims; if any one is dropped, the methodology no longer holds. FramingInvariants are mistakes that violate these axioms.';
