-- ----------------------------------------------------------------------------
-- PlatformFeatures: The catalog of distinctive features the ERB platform offers. The rulebook is the formal SSoT for this list; the repo's README and per-feature README files MUST conform to these rows. Each feature has a one-line summary (the elevator pitch), a Tier (headline vs additional), a Priority (sort order within tier), and a ReadmeFilePath (where the long-form explanation lives — even if it's still a stub). IsReadmeStub is calculated so 'which READMEs are still missing' is a queryable fact, not a tribal one. Many features reference an OntologyAxiom — that's the axiom the feature operationalizes.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS platform_features (
  feature_id                          TEXT                 PRIMARY KEY          -- Stable PK, e.g. feature-001
);
ALTER TABLE platform_features ADD COLUMN IF NOT EXISTS name TEXT;                                   -- Full feature name as it appears in headings
ALTER TABLE platform_features ADD COLUMN IF NOT EXISTS short_name TEXT;                             -- Short identifier for cross-references (e.g. 'ADP', 'Hub-and-Spoke')
ALTER TABLE platform_features ADD COLUMN IF NOT EXISTS tier TEXT;                                   -- headline | additional — drives the two README sections
ALTER TABLE platform_features ADD COLUMN IF NOT EXISTS priority NUMERIC;                            -- Sort order within tier (lower = higher up)
ALTER TABLE platform_features ADD COLUMN IF NOT EXISTS one_line_summary TEXT;                       -- The elevator pitch — one sentence, no clauses about hypotheticals
ALTER TABLE platform_features ADD COLUMN IF NOT EXISTS readme_file_path TEXT;                       -- Path to the per-feature README, relative to repo root. Hand-maintained but MUST conform to this row.
ALTER TABLE platform_features ADD COLUMN IF NOT EXISTS readme_stub_content TEXT;                    -- The placeholder one-sentence body that ships in the README until it's fleshed out. Lets us hand-maintain READMEs while keeping the rulebook authoritative for the seed content.
ALTER TABLE platform_features ADD COLUMN IF NOT EXISTS readme_length NUMERIC;                       -- Best-known character count of the README file on disk. Populated by a tooling pass; null means 'not yet measured'. Used to compute IsReadmeStub.
ALTER TABLE platform_features ADD COLUMN IF NOT EXISTS status TEXT;                                 -- shipped | partial | planned — current implementation status
COMMENT ON TABLE platform_features IS 'The catalog of distinctive features the ERB platform offers. The rulebook is the formal SSoT for this list; the repo''s README and per-feature README files MUST conform to these rows. Each feature has a one-line summary (the elevator pitch), a Tier (headline vs additional), a Priority (sort order within tier), and a ReadmeFilePath (where the long-form explanation lives — even if it''s still a stub). IsReadmeStub is calculated so ''which READMEs are still missing'' is a queryable fact, not a tribal one. Many features reference an OntologyAxiom — that''s the axiom the feature operationalizes.';
COMMENT ON COLUMN platform_features.feature_id IS 'Stable PK, e.g. feature-001';
COMMENT ON COLUMN platform_features.name IS 'Full feature name as it appears in headings';
COMMENT ON COLUMN platform_features.short_name IS 'Short identifier for cross-references (e.g. ''ADP'', ''Hub-and-Spoke'')';
COMMENT ON COLUMN platform_features.tier IS 'headline | additional — drives the two README sections';
COMMENT ON COLUMN platform_features.priority IS 'Sort order within tier (lower = higher up)';
COMMENT ON COLUMN platform_features.one_line_summary IS 'The elevator pitch — one sentence, no clauses about hypotheticals';
COMMENT ON COLUMN platform_features.readme_file_path IS 'Path to the per-feature README, relative to repo root. Hand-maintained but MUST conform to this row.';
COMMENT ON COLUMN platform_features.readme_stub_content IS 'The placeholder one-sentence body that ships in the README until it''s fleshed out. Lets us hand-maintain READMEs while keeping the rulebook authoritative for the seed content.';
COMMENT ON COLUMN platform_features.readme_length IS 'Best-known character count of the README file on disk. Populated by a tooling pass; null means ''not yet measured''. Used to compute IsReadmeStub.';
COMMENT ON COLUMN platform_features.status IS 'shipped | partial | planned — current implementation status';

