COMMENT ON TABLE user_roles IS 'Admin portal access tiers. Each role is a PERSONA with its own landing screen, tagline, and bespoke screen overrides (see RoleScreenHints). NOT a CRUD form — every role gets a UX shaped for what that person actually cares about. Also drives RLS policies that Postgres applies to portal writes.';
COMMENT ON COLUMN user_roles.persona IS 'One-line description of WHO this role is — the kind of person who logs in as this role';
COMMENT ON COLUMN user_roles.tagline IS 'Short motto shown on the role''s landing screen — sets the mood';
COMMENT ON COLUMN user_roles.primary_concerns IS 'What this role spends time on. Comma-separated, used by the home screen to bubble these things up.';
COMMENT ON COLUMN user_roles.color_theme IS 'CSS accent colour for the role''s pill / chrome — quick visual identity';
COMMENT ON COLUMN user_roles.access_level IS 'read | write | full-admin';
COMMENT ON COLUMN user_roles.can_access_tech_tools IS 'Tech Tools nest = raw Postgres explorer, ssotme-proxy logs, conformance internals';

-- ----------------------------------------------------------------------------
-- AppPermissions: RLS-style policy table: declarative per-role allow/deny on portal API endpoints and on Postgres tables. Generated into Postgres on portal bootstrap as RLS policies.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS app_permissions (
  permission_id                       TEXT                 PRIMARY KEY
);
ALTER TABLE app_permissions ADD COLUMN IF NOT EXISTS resource TEXT;                                 -- Logical resource: rulebook.entity, rulebook.field, rulebook.formula, build, test, users, tech-tools.postgres, tech-tools.proxy
ALTER TABLE app_permissions ADD COLUMN IF NOT EXISTS "action" TEXT;                                 -- read | create | update | delete | execute
ALTER TABLE app_permissions ADD COLUMN IF NOT EXISTS allow BOOLEAN;
ALTER TABLE app_permissions ADD COLUMN IF NOT EXISTS rls_predicate TEXT;                            -- Postgres RLS USING clause (when applicable); null for endpoint-only checks
COMMENT ON TABLE app_permissions IS 'RLS-style policy table: declarative per-role allow/deny on portal API endpoints and on Postgres tables. Generated into Postgres on portal bootstrap as RLS policies.';
COMMENT ON COLUMN app_permissions.resource IS 'Logical resource: rulebook.entity, rulebook.field, rulebook.formula, build, test, users, tech-tools.postgres, tech-tools.proxy';
COMMENT ON COLUMN app_permissions."action" IS 'read | create | update | delete | execute';
COMMENT ON COLUMN app_permissions.rls_predicate IS 'Postgres RLS USING clause (when applicable); null for endpoint-only checks';

