ALTER TABLE app_navigation ADD COLUMN IF NOT EXISTS nav_area TEXT;                                  -- Persona/area bucket: main (everyone), admin (CRUD ops), developer (build/test/tech), docs (educational/training). Drives sidebar section grouping and route prefix.
COMMENT ON TABLE app_navigation IS 'Primary navigation tree for the admin portal. Drives the left sidebar. Each node has a role gate and a target screen. This is the developer''s narrative through a rulebook project.';
COMMENT ON COLUMN app_navigation.icon IS 'Lucide icon name';
COMMENT ON COLUMN app_navigation.story_beat IS 'What this node teaches the developer in the rulebook narrative';
COMMENT ON COLUMN app_navigation.nav_area IS 'Persona/area bucket: main (everyone), admin (CRUD ops), developer (build/test/tech), docs (educational/training). Drives sidebar section grouping and route prefix.';

