ALTER TABLE app_screens ADD COLUMN IF NOT EXISTS primary_action TEXT;
ALTER TABLE app_screens ADD COLUMN IF NOT EXISTS story TEXT;                                        -- What the developer learns / does on this screen
ALTER TABLE app_screens ADD COLUMN IF NOT EXISTS nav_area TEXT;                                     -- Which persona area this screen belongs to. Drives route prefix and sidebar section.
