COMMENT ON COLUMN app_screens.reads_entities IS 'Comma-separated rulebook entities the screen reads';
COMMENT ON COLUMN app_screens.writes_entities IS 'Comma-separated rulebook entities the screen mutates (developer-only)';
COMMENT ON COLUMN app_screens.layout IS 'split-detail | list | grid | dashboard | editor';
COMMENT ON COLUMN app_screens.story IS 'What the developer learns / does on this screen';
COMMENT ON COLUMN app_screens.nav_area IS 'Which persona area this screen belongs to. Drives route prefix and sidebar section.';

