ALTER TABLE add_tool_catalog ADD COLUMN IF NOT EXISTS install_url TEXT;                             -- URL passed to `effortless -install`
ALTER TABLE add_tool_catalog ADD COLUMN IF NOT EXISTS output_path TEXT;                             -- Default RelativePath under the project (e.g. /python, /golang)
