-- ----------------------------------------------------------------------------
-- RulebookFlavors: Classification of each demo rulebook under rulebook-examples/. Lets the UI group projects by what they're TEACHING — a tutorial ladder is a different beast from a computation-heavy ontology. Density numbers come from a static analysis of each rulebook (calculated/aggregation/lookup counts).
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS rulebook_flavors (
  flavor_id                           TEXT                 PRIMARY KEY
);
ALTER TABLE rulebook_flavors ADD COLUMN IF NOT EXISTS sort_order NUMERIC;                           -- Ascending integer; drives default display order in the portal. Lower = shown first. Tutorial-ladder projects sort before demos; demos before meta/graph.
ALTER TABLE rulebook_flavors ADD COLUMN IF NOT EXISTS project_slug TEXT;                            -- Folder under rulebook-examples/ — also the active-domain.txt value
ALTER TABLE rulebook_flavors ADD COLUMN IF NOT EXISTS display_name TEXT;
ALTER TABLE rulebook_flavors ADD COLUMN IF NOT EXISTS tagline TEXT;
ALTER TABLE rulebook_flavors ADD COLUMN IF NOT EXISTS logo_path TEXT;
ALTER TABLE rulebook_flavors ADD COLUMN IF NOT EXISTS flavor TEXT;                                  -- crud-template | computation-heavy | aggregation-heavy | graph-ontology | meta-rulebook | tutorial-ladder
ALTER TABLE rulebook_flavors ADD COLUMN IF NOT EXISTS complexity TEXT;                              -- minimal | basic | advanced
ALTER TABLE rulebook_flavors ADD COLUMN IF NOT EXISTS entity_count NUMERIC;
ALTER TABLE rulebook_flavors ADD COLUMN IF NOT EXISTS calculated_count NUMERIC;                     -- Number of calculated fields
ALTER TABLE rulebook_flavors ADD COLUMN IF NOT EXISTS aggregation_count NUMERIC;
ALTER TABLE rulebook_flavors ADD COLUMN IF NOT EXISTS lookup_count NUMERIC;
ALTER TABLE rulebook_flavors ADD COLUMN IF NOT EXISTS learning_focus TEXT;                          -- What this demo is designed to teach
ALTER TABLE rulebook_flavors ADD COLUMN IF NOT EXISTS good_answer_key_for TEXT;                     -- Substrate(s) this demo makes a particularly good answer-key witness for — when applicable
COMMENT ON TABLE rulebook_flavors IS 'Classification of each demo rulebook under rulebook-examples/. Lets the UI group projects by what they''re TEACHING — a tutorial ladder is a different beast from a computation-heavy ontology. Density numbers come from a static analysis of each rulebook (calculated/aggregation/lookup counts).';
COMMENT ON COLUMN rulebook_flavors.sort_order IS 'Ascending integer; drives default display order in the portal. Lower = shown first. Tutorial-ladder projects sort before demos; demos before meta/graph.';
COMMENT ON COLUMN rulebook_flavors.project_slug IS 'Folder under rulebook-examples/ — also the active-domain.txt value';
COMMENT ON COLUMN rulebook_flavors.flavor IS 'crud-template | computation-heavy | aggregation-heavy | graph-ontology | meta-rulebook | tutorial-ladder';
COMMENT ON COLUMN rulebook_flavors.complexity IS 'minimal | basic | advanced';
COMMENT ON COLUMN rulebook_flavors.calculated_count IS 'Number of calculated fields';
COMMENT ON COLUMN rulebook_flavors.learning_focus IS 'What this demo is designed to teach';
COMMENT ON COLUMN rulebook_flavors.good_answer_key_for IS 'Substrate(s) this demo makes a particularly good answer-key witness for — when applicable';

-- ----------------------------------------------------------------------------
-- FieldTypeTaxonomy: Names every field-type the rulebook supports, with intent and example formula shape. Lets the UI explain what makes a calculated field different from a lookup field from an aggregation, instead of just showing a type tag.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS field_type_taxonomy (
  type_id                             TEXT                 PRIMARY KEY
);
ALTER TABLE field_type_taxonomy ADD COLUMN IF NOT EXISTS type_name TEXT;                            -- The string that appears in schema[].type
ALTER TABLE field_type_taxonomy ADD COLUMN IF NOT EXISTS intent TEXT;                               -- What this type is FOR — one sentence
ALTER TABLE field_type_taxonomy ADD COLUMN IF NOT EXISTS example_formula TEXT;                      -- A representative formula or definition shape
ALTER TABLE field_type_taxonomy ADD COLUMN IF NOT EXISTS storage_mode TEXT;                         -- stored | derived-at-read | derived-at-write — where this field's value lives
ALTER TABLE field_type_taxonomy ADD COLUMN IF NOT EXISTS read_only_in_ui BOOLEAN;                   -- True if the portal should never let users edit this field's value directly
ALTER TABLE field_type_taxonomy ADD COLUMN IF NOT EXISTS expressive_tier TEXT;                      -- Which substrate ExpressiveCompleteness tier is required to faithfully evaluate this — full | partial-formula | partial-aggregation | shape-only
COMMENT ON TABLE field_type_taxonomy IS 'Names every field-type the rulebook supports, with intent and example formula shape. Lets the UI explain what makes a calculated field different from a lookup field from an aggregation, instead of just showing a type tag.';
COMMENT ON COLUMN field_type_taxonomy.type_name IS 'The string that appears in schema[].type';
COMMENT ON COLUMN field_type_taxonomy.intent IS 'What this type is FOR — one sentence';
COMMENT ON COLUMN field_type_taxonomy.example_formula IS 'A representative formula or definition shape';
COMMENT ON COLUMN field_type_taxonomy.storage_mode IS 'stored | derived-at-read | derived-at-write — where this field''s value lives';
COMMENT ON COLUMN field_type_taxonomy.read_only_in_ui IS 'True if the portal should never let users edit this field''s value directly';
COMMENT ON COLUMN field_type_taxonomy.expressive_tier IS 'Which substrate ExpressiveCompleteness tier is required to faithfully evaluate this — full | partial-formula | partial-aggregation | shape-only';

-- ----------------------------------------------------------------------------
-- RoleScreenHints: Per-(role, screen) bespoke UX overrides. The base AppScreens row says WHAT the screen is; this table says HOW IT SHOULD FEEL FOR THIS ROLE. The hints are intentionally prescriptive enough that two different agents implementing the screen for the same role would land on the same flow.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS role_screen_hints (
  hint_id                             TEXT                 PRIMARY KEY
);
ALTER TABLE role_screen_hints ADD COLUMN IF NOT EXISTS layout TEXT;                                 -- Override AppScreens.Layout for this role (e.g. Reviewer sees Tests as 'matrix-first', Ops sees Builds as 'last-build-banner')
ALTER TABLE role_screen_hints ADD COLUMN IF NOT EXISTS emphasis TEXT;                               -- What this role wants to see first when they land here — the dominant visual element
ALTER TABLE role_screen_hints ADD COLUMN IF NOT EXISTS hide TEXT;                                   -- Comma-separated list of UI elements this role should not see on this screen
ALTER TABLE role_screen_hints ADD COLUMN IF NOT EXISTS primary_actions TEXT;                        -- Comma-separated, the buttons that should be prominent for this role
ALTER TABLE role_screen_hints ADD COLUMN IF NOT EXISTS implementation_hints TEXT;                   -- Prescriptive description of the screen for this role. Detailed enough that two agents building it would land on the same flow.
COMMENT ON TABLE role_screen_hints IS 'Per-(role, screen) bespoke UX overrides. The base AppScreens row says WHAT the screen is; this table says HOW IT SHOULD FEEL FOR THIS ROLE. The hints are intentionally prescriptive enough that two different agents implementing the screen for the same role would land on the same flow.';
COMMENT ON COLUMN role_screen_hints.layout IS 'Override AppScreens.Layout for this role (e.g. Reviewer sees Tests as ''matrix-first'', Ops sees Builds as ''last-build-banner'')';
COMMENT ON COLUMN role_screen_hints.emphasis IS 'What this role wants to see first when they land here — the dominant visual element';
COMMENT ON COLUMN role_screen_hints.hide IS 'Comma-separated list of UI elements this role should not see on this screen';
COMMENT ON COLUMN role_screen_hints.primary_actions IS 'Comma-separated, the buttons that should be prominent for this role';
COMMENT ON COLUMN role_screen_hints.implementation_hints IS 'Prescriptive description of the screen for this role. Detailed enough that two agents building it would land on the same flow.';

-- ----------------------------------------------------------------------------
-- ClickTargets: Canonical in-app navigation affordances. Every clickable element in the portal should be listed here with where the click goes. Two agents implementing different screens would both consult this table to wire up cross-screen jumps. NOT the Explain-DAG — this is page-to-page navigation: 'Orders: 5' is clickable and goes to a page filtered to those 5 orders. NOT documentation-style 'learn more' links.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS click_targets (
  click_id                            TEXT                 PRIMARY KEY
);
ALTER TABLE click_targets ADD COLUMN IF NOT EXISTS from_kind TEXT;                                  -- What you're clicking on — entity-row,field-row,formula-cell,substrate-row,test-cell,role-pill,user-row,nav-card,count-number,fk-value,flavor-tag,framing-invariant,axiom
ALTER TABLE click_targets ADD COLUMN IF NOT EXISTS from_context TEXT;                               -- Where this click affordance lives — e.g. 'home-card:substrates' or 'entity-detail:fk-field'
ALTER TABLE click_targets ADD COLUMN IF NOT EXISTS to_path TEXT;                                    -- React-router-style path, with :param tokens that the caller fills in. e.g. /rulebook/entities/:entity?field=:field
ALTER TABLE click_targets ADD COLUMN IF NOT EXISTS filter TEXT;                                     -- Query-string filter the target page should pre-apply
ALTER TABLE click_targets ADD COLUMN IF NOT EXISTS story TEXT;                                      -- Plain-English: 'Click Orders: 5 → see those 5 orders'. Anchor for implementer.
COMMENT ON TABLE click_targets IS 'Canonical in-app navigation affordances. Every clickable element in the portal should be listed here with where the click goes. Two agents implementing different screens would both consult this table to wire up cross-screen jumps. NOT the Explain-DAG — this is page-to-page navigation: ''Orders: 5'' is clickable and goes to a page filtered to those 5 orders. NOT documentation-style ''learn more'' links.';
COMMENT ON COLUMN click_targets.from_kind IS 'What you''re clicking on — entity-row,field-row,formula-cell,substrate-row,test-cell,role-pill,user-row,nav-card,count-number,fk-value,flavor-tag,framing-invariant,axiom';
COMMENT ON COLUMN click_targets.from_context IS 'Where this click affordance lives — e.g. ''home-card:substrates'' or ''entity-detail:fk-field''';
COMMENT ON COLUMN click_targets.to_path IS 'React-router-style path, with :param tokens that the caller fills in. e.g. /rulebook/entities/:entity?field=:field';
COMMENT ON COLUMN click_targets.filter IS 'Query-string filter the target page should pre-apply';
COMMENT ON COLUMN click_targets.story IS 'Plain-English: ''Click Orders: 5 → see those 5 orders''. Anchor for implementer.';

-- ----------------------------------------------------------------------------
-- SubstrateContractPhases: The three-phase contract every execution substrate implements. Inject is structural (schema → SDK), Execute is functional (compute), Grade is comparison. All three are 100% domain-agnostic — they translate whatever the rulebook defines without knowing what it means. Together with EvaluationSteps (the substeps within each phase) and EvaluationArtifacts (the JSON files that flow between phases), this forms the full evaluation subgraph: Phase → Steps → Artifacts.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS substrate_contract_phases (
  phase_id                            TEXT                 PRIMARY KEY
);
ALTER TABLE substrate_contract_phases ADD COLUMN IF NOT EXISTS "order" INTEGER;
ALTER TABLE substrate_contract_phases ADD COLUMN IF NOT EXISTS name TEXT;
ALTER TABLE substrate_contract_phases ADD COLUMN IF NOT EXISTS domain_agnostic BOOLEAN;             -- Whether this phase's code is generic across all rulebooks. All three are true by design.
ALTER TABLE substrate_contract_phases ADD COLUMN IF NOT EXISTS input TEXT;
ALTER TABLE substrate_contract_phases ADD COLUMN IF NOT EXISTS output TEXT;
ALTER TABLE substrate_contract_phases ADD COLUMN IF NOT EXISTS script_pattern TEXT;                 -- Filename pattern under each execution-substrates/<technology>/ folder.
ALTER TABLE substrate_contract_phases ADD COLUMN IF NOT EXISTS description TEXT;
ALTER TABLE substrate_contract_phases ADD COLUMN IF NOT EXISTS why_domain_agnostic TEXT;            -- Explains how this phase remains generic — i.e. what it must NOT contain.
ALTER TABLE substrate_contract_phases ADD COLUMN IF NOT EXISTS input_artifact_id TEXT;              -- FK to EvaluationArtifacts.ArtifactId — the canonical input artifact this phase consumes.
ALTER TABLE substrate_contract_phases ADD COLUMN IF NOT EXISTS output_artifact_id TEXT;             -- FK to EvaluationArtifacts.ArtifactId — the canonical output artifact this phase produces.
ALTER TABLE substrate_contract_phases ADD COLUMN IF NOT EXISTS failure_mode TEXT;                   -- What going wrong in this phase actually looks like — e.g. injector emits a domain word, execute calls a hand-written helper, grader hides field-level disagreement.
COMMENT ON TABLE substrate_contract_phases IS 'The three-phase contract every execution substrate implements. Inject is structural (schema → SDK), Execute is functional (compute), Grade is comparison. All three are 100% domain-agnostic — they translate whatever the rulebook defines without knowing what it means. Together with EvaluationSteps (the substeps within each phase) and EvaluationArtifacts (the JSON files that flow between phases), this forms the full evaluation subgraph: Phase → Steps → Artifacts.';
COMMENT ON COLUMN substrate_contract_phases.domain_agnostic IS 'Whether this phase''s code is generic across all rulebooks. All three are true by design.';
COMMENT ON COLUMN substrate_contract_phases.script_pattern IS 'Filename pattern under each execution-substrates/<technology>/ folder.';
COMMENT ON COLUMN substrate_contract_phases.why_domain_agnostic IS 'Explains how this phase remains generic — i.e. what it must NOT contain.';
COMMENT ON COLUMN substrate_contract_phases.input_artifact_id IS 'FK to EvaluationArtifacts.ArtifactId — the canonical input artifact this phase consumes.';
COMMENT ON COLUMN substrate_contract_phases.output_artifact_id IS 'FK to EvaluationArtifacts.ArtifactId — the canonical output artifact this phase produces.';
COMMENT ON COLUMN substrate_contract_phases.failure_mode IS 'What going wrong in this phase actually looks like — e.g. injector emits a domain word, execute calls a hand-written helper, grader hides field-level disagreement.';

-- ----------------------------------------------------------------------------
-- EvaluationSteps: Substeps within each SubstrateContractPhase. Inject, Execute, and Grade each decompose into a small number of concrete substeps the orchestrator executes in order. This is the layer below SubstrateContractPhases — it answers 'what specifically happens inside phase-execute?' Used by the admin portal's Tests screen to render the actual stages a substrate run goes through.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS evaluation_steps (
  step_id                             TEXT                 PRIMARY KEY
);
ALTER TABLE evaluation_steps ADD COLUMN IF NOT EXISTS phase_id TEXT;                                -- FK to SubstrateContractPhases.PhaseId.
ALTER TABLE evaluation_steps ADD COLUMN IF NOT EXISTS "order" INTEGER;                              -- Order within the parent phase.
ALTER TABLE evaluation_steps ADD COLUMN IF NOT EXISTS name TEXT;
ALTER TABLE evaluation_steps ADD COLUMN IF NOT EXISTS description TEXT;
ALTER TABLE evaluation_steps ADD COLUMN IF NOT EXISTS mechanism TEXT;                               -- The actual code path — script file, function, or pipeline stage.
ALTER TABLE evaluation_steps ADD COLUMN IF NOT EXISTS invariant TEXT;                               -- A rule this step must preserve to remain domain-agnostic / conformance-preserving.
COMMENT ON TABLE evaluation_steps IS 'Substeps within each SubstrateContractPhase. Inject, Execute, and Grade each decompose into a small number of concrete substeps the orchestrator executes in order. This is the layer below SubstrateContractPhases — it answers ''what specifically happens inside phase-execute?'' Used by the admin portal''s Tests screen to render the actual stages a substrate run goes through.';
COMMENT ON COLUMN evaluation_steps.phase_id IS 'FK to SubstrateContractPhases.PhaseId.';
COMMENT ON COLUMN evaluation_steps."order" IS 'Order within the parent phase.';
COMMENT ON COLUMN evaluation_steps.mechanism IS 'The actual code path — script file, function, or pipeline stage.';
COMMENT ON COLUMN evaluation_steps.invariant IS 'A rule this step must preserve to remain domain-agnostic / conformance-preserving.';

-- ----------------------------------------------------------------------------
-- EvaluationArtifacts: The JSON / Markdown files that flow between SubstrateContractPhases. Each artifact is a contract: a file with a known schema produced by one phase and consumed by the next. This table is the artifact registry — what each file IS, where it lives, who writes it, who reads it. Together with SubstrateContractPhases.InputArtifactId/OutputArtifactId, this gives the evaluation pipeline a fully-witnessed data-flow graph.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS evaluation_artifacts (
  artifact_id                         TEXT                 PRIMARY KEY
);
ALTER TABLE evaluation_artifacts ADD COLUMN IF NOT EXISTS name TEXT;
ALTER TABLE evaluation_artifacts ADD COLUMN IF NOT EXISTS format TEXT;                              -- json | markdown | html | binary | source-tree
ALTER TABLE evaluation_artifacts ADD COLUMN IF NOT EXISTS path_pattern TEXT;                        -- Where the artifact lives on disk, with <placeholders> for variable parts.
ALTER TABLE evaluation_artifacts ADD COLUMN IF NOT EXISTS produced_by_phase_id TEXT;                -- FK to SubstrateContractPhases.PhaseId — the phase that writes this artifact. Null for inputs that come from outside the evaluation pipeline (e.g. the rulebook itself).
ALTER TABLE evaluation_artifacts ADD COLUMN IF NOT EXISTS consumed_by_phase_id TEXT;                -- FK to SubstrateContractPhases.PhaseId — the phase that reads this artifact. Null for terminal outputs (e.g. the human-facing report).
ALTER TABLE evaluation_artifacts ADD COLUMN IF NOT EXISTS derived_from TEXT;                        -- Plain-text description of how this artifact is derived — important for proving no substrate is privileged.
ALTER TABLE evaluation_artifacts ADD COLUMN IF NOT EXISTS description TEXT;
COMMENT ON TABLE evaluation_artifacts IS 'The JSON / Markdown files that flow between SubstrateContractPhases. Each artifact is a contract: a file with a known schema produced by one phase and consumed by the next. This table is the artifact registry — what each file IS, where it lives, who writes it, who reads it. Together with SubstrateContractPhases.InputArtifactId/OutputArtifactId, this gives the evaluation pipeline a fully-witnessed data-flow graph.';
COMMENT ON COLUMN evaluation_artifacts.format IS 'json | markdown | html | binary | source-tree';
COMMENT ON COLUMN evaluation_artifacts.path_pattern IS 'Where the artifact lives on disk, with <placeholders> for variable parts.';
COMMENT ON COLUMN evaluation_artifacts.produced_by_phase_id IS 'FK to SubstrateContractPhases.PhaseId — the phase that writes this artifact. Null for inputs that come from outside the evaluation pipeline (e.g. the rulebook itself).';
COMMENT ON COLUMN evaluation_artifacts.consumed_by_phase_id IS 'FK to SubstrateContractPhases.PhaseId — the phase that reads this artifact. Null for terminal outputs (e.g. the human-facing report).';
COMMENT ON COLUMN evaluation_artifacts.derived_from IS 'Plain-text description of how this artifact is derived — important for proving no substrate is privileged.';

-- ----------------------------------------------------------------------------
-- SubstrateTradeoffDimensions: The fixed taxonomy of dimensions used to characterize every substrate. Pro/con statements in SubstrateTradeoffs are scoped to one of these dimensions, so substrates can be compared apples-to-apples (e.g. 'who's fastest?' = filter SubstrateTradeoffs by DimensionId=dim-speed). Adding a dimension here means committing to fill it in for every substrate.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS substrate_tradeoff_dimensions (
  dimension_id                        TEXT                 PRIMARY KEY
);
ALTER TABLE substrate_tradeoff_dimensions ADD COLUMN IF NOT EXISTS name TEXT;
ALTER TABLE substrate_tradeoff_dimensions ADD COLUMN IF NOT EXISTS description TEXT;
ALTER TABLE substrate_tradeoff_dimensions ADD COLUMN IF NOT EXISTS "order" INTEGER;                 -- Display order in UI.
COMMENT ON TABLE substrate_tradeoff_dimensions IS 'The fixed taxonomy of dimensions used to characterize every substrate. Pro/con statements in SubstrateTradeoffs are scoped to one of these dimensions, so substrates can be compared apples-to-apples (e.g. ''who''s fastest?'' = filter SubstrateTradeoffs by DimensionId=dim-speed). Adding a dimension here means committing to fill it in for every substrate.';
COMMENT ON COLUMN substrate_tradeoff_dimensions."order" IS 'Display order in UI.';

-- ----------------------------------------------------------------------------
-- SubstrateTradeoffs: Per-(Substrate × Dimension) Pro/Con/Note. The same fixed dimension set (see SubstrateTradeoffDimensions) is applied to every substrate, so 'why pick Postgres over Python?' or 'why does English cost so much?' is answerable by filtering this table. NOT a ranking — see ax-002 (no privileged substrate). Each row records a factual property along one comparable axis.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS substrate_tradeoffs (
  tradeoff_id                         TEXT                 PRIMARY KEY
);
ALTER TABLE substrate_tradeoffs ADD COLUMN IF NOT EXISTS substrate_id TEXT;                         -- FK to ExecutionSubstrates.SubstrateId.
ALTER TABLE substrate_tradeoffs ADD COLUMN IF NOT EXISTS dimension_id TEXT;                         -- FK to SubstrateTradeoffDimensions.DimensionId.
ALTER TABLE substrate_tradeoffs ADD COLUMN IF NOT EXISTS pro TEXT;                                  -- What this substrate does WELL along this dimension. Null if neutral or weak.
ALTER TABLE substrate_tradeoffs ADD COLUMN IF NOT EXISTS con TEXT;                                  -- What this substrate does POORLY along this dimension. Null if neutral or strong.
ALTER TABLE substrate_tradeoffs ADD COLUMN IF NOT EXISTS note TEXT;                                 -- Additional context — e.g. quantitative observation, edge case, source of measurement.
COMMENT ON TABLE substrate_tradeoffs IS 'Per-(Substrate × Dimension) Pro/Con/Note. The same fixed dimension set (see SubstrateTradeoffDimensions) is applied to every substrate, so ''why pick Postgres over Python?'' or ''why does English cost so much?'' is answerable by filtering this table. NOT a ranking — see ax-002 (no privileged substrate). Each row records a factual property along one comparable axis.';
COMMENT ON COLUMN substrate_tradeoffs.substrate_id IS 'FK to ExecutionSubstrates.SubstrateId.';
COMMENT ON COLUMN substrate_tradeoffs.dimension_id IS 'FK to SubstrateTradeoffDimensions.DimensionId.';
COMMENT ON COLUMN substrate_tradeoffs.pro IS 'What this substrate does WELL along this dimension. Null if neutral or weak.';
COMMENT ON COLUMN substrate_tradeoffs.con IS 'What this substrate does POORLY along this dimension. Null if neutral or strong.';
COMMENT ON COLUMN substrate_tradeoffs.note IS 'Additional context — e.g. quantitative observation, edge case, source of measurement.';

-- ----------------------------------------------------------------------------
-- FuzzyGradingProviders: LLM providers usable for fuzzy grading of the English substrate — the ONLY non-deterministic substrate. All other substrates execute formulas deterministically; English requires an LLM to interpret prose into computed values. Use low temperature (0.1) for repeatability.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS fuzzy_grading_providers (
  provider_id                         TEXT                 PRIMARY KEY
);
ALTER TABLE fuzzy_grading_providers ADD COLUMN IF NOT EXISTS name TEXT;
ALTER TABLE fuzzy_grading_providers ADD COLUMN IF NOT EXISTS model TEXT;
ALTER TABLE fuzzy_grading_providers ADD COLUMN IF NOT EXISTS env_var TEXT;                          -- Environment variable holding the API key. Null for local providers.
ALTER TABLE fuzzy_grading_providers ADD COLUMN IF NOT EXISTS determinism TEXT;                      -- 'non-deterministic' for all LLMs; low temperature reduces variance but does not eliminate it.
ALTER TABLE fuzzy_grading_providers ADD COLUMN IF NOT EXISTS typical_accuracy TEXT;                 -- Observed conformance on the English substrate against deterministic answer keys.
ALTER TABLE fuzzy_grading_providers ADD COLUMN IF NOT EXISTS speed_relative_to_deterministic TEXT;  -- Order-of-magnitude slowdown vs. a deterministic substrate like Python or Postgres.
ALTER TABLE fuzzy_grading_providers ADD COLUMN IF NOT EXISTS local_runtime BOOLEAN;                 -- True if runnable without network.
ALTER TABLE fuzzy_grading_providers ADD COLUMN IF NOT EXISTS notes TEXT;
COMMENT ON TABLE fuzzy_grading_providers IS 'LLM providers usable for fuzzy grading of the English substrate — the ONLY non-deterministic substrate. All other substrates execute formulas deterministically; English requires an LLM to interpret prose into computed values. Use low temperature (0.1) for repeatability.';
COMMENT ON COLUMN fuzzy_grading_providers.env_var IS 'Environment variable holding the API key. Null for local providers.';
COMMENT ON COLUMN fuzzy_grading_providers.determinism IS '''non-deterministic'' for all LLMs; low temperature reduces variance but does not eliminate it.';
COMMENT ON COLUMN fuzzy_grading_providers.typical_accuracy IS 'Observed conformance on the English substrate against deterministic answer keys.';
COMMENT ON COLUMN fuzzy_grading_providers.speed_relative_to_deterministic IS 'Order-of-magnitude slowdown vs. a deterministic substrate like Python or Postgres.';
COMMENT ON COLUMN fuzzy_grading_providers.local_runtime IS 'True if runnable without network.';

-- ----------------------------------------------------------------------------
-- FormulaDialects: Catalog of formula dialects that a rulebook can declare. Per-rulebook formula dialect is headline feature #6: each demo rulebook names which dialect it speaks (in _meta.formulaDialect), and substrates honor that declaration. The platform rulebook does not enumerate which functions a dialect supports — that lives in each demo rulebook's own formula definitions. This catalog only registers the dialects themselves.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS formula_dialects (
  dialect_id                          TEXT                 PRIMARY KEY
);
ALTER TABLE formula_dialects ADD COLUMN IF NOT EXISTS name TEXT;
ALTER TABLE formula_dialects ADD COLUMN IF NOT EXISTS origin TEXT;                                  -- Where the dialect's surface syntax comes from (Excel, Airtable, etc.).
ALTER TABLE formula_dialects ADD COLUMN IF NOT EXISTS field_ref_syntax TEXT;                        -- How a rulebook formula references another field.
ALTER TABLE formula_dialects ADD COLUMN IF NOT EXISTS string_concat TEXT;                           -- How strings are concatenated in this dialect.
ALTER TABLE formula_dialects ADD COLUMN IF NOT EXISTS case_sensitive BOOLEAN;
ALTER TABLE formula_dialects ADD COLUMN IF NOT EXISTS example_formula TEXT;
ALTER TABLE formula_dialects ADD COLUMN IF NOT EXISTS primary_substrates TEXT;                      -- Substrates that have the richest support for this dialect.
ALTER TABLE formula_dialects ADD COLUMN IF NOT EXISTS status TEXT;                                  -- active | experimental | deprecated
ALTER TABLE formula_dialects ADD COLUMN IF NOT EXISTS notes TEXT;
COMMENT ON TABLE formula_dialects IS 'Catalog of formula dialects that a rulebook can declare. Per-rulebook formula dialect is headline feature #6: each demo rulebook names which dialect it speaks (in _meta.formulaDialect), and substrates honor that declaration. The platform rulebook does not enumerate which functions a dialect supports — that lives in each demo rulebook''s own formula definitions. This catalog only registers the dialects themselves.';
COMMENT ON COLUMN formula_dialects.origin IS 'Where the dialect''s surface syntax comes from (Excel, Airtable, etc.).';
COMMENT ON COLUMN formula_dialects.field_ref_syntax IS 'How a rulebook formula references another field.';
COMMENT ON COLUMN formula_dialects.string_concat IS 'How strings are concatenated in this dialect.';
COMMENT ON COLUMN formula_dialects.primary_substrates IS 'Substrates that have the richest support for this dialect.';
COMMENT ON COLUMN formula_dialects.status IS 'active | experimental | deprecated';

-- ----------------------------------------------------------------------------
-- DemoNarratives: Curated narratives that demonstrate ERB capabilities in motion: substrates 'follow along' as the rulebook changes. Two narrative styles coexist: (1) commit-sequence narratives (legacy) where a single demo rulebook evolves over commits; (2) cross-rulebook narratives (current) where the same demo is observed across DIFFERENT rulebooks side-by-side. Cross-rulebook supersedes commit-sequence because RulebookDomains now form a tree (ParentDomainId) — the progression is data, not git history.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS demo_narratives (
  narrative_id                        TEXT                 PRIMARY KEY
);
ALTER TABLE demo_narratives ADD COLUMN IF NOT EXISTS "order" INTEGER;                               -- Order within the narrative sequence.
ALTER TABLE demo_narratives ADD COLUMN IF NOT EXISTS narrative_name TEXT;                           -- Name of the overall narrative this step belongs to.
ALTER TABLE demo_narratives ADD COLUMN IF NOT EXISTS step_name TEXT;
ALTER TABLE demo_narratives ADD COLUMN IF NOT EXISTS related_domain_id TEXT;                        -- FK to RulebookDomains.DomainId, when this step uses a specific demo rulebook.
ALTER TABLE demo_narratives ADD COLUMN IF NOT EXISTS what_happens TEXT;
ALTER TABLE demo_narratives ADD COLUMN IF NOT EXISTS key_lesson TEXT;
ALTER TABLE demo_narratives ADD COLUMN IF NOT EXISTS observed_cost TEXT;                            -- Per-substrate cost observation (e.g. 'OWL 10s, English 5min').
ALTER TABLE demo_narratives ADD COLUMN IF NOT EXISTS narrative_style TEXT;                          -- commit-sequence (legacy) | cross-rulebook (current) — how the steps are realized at demo time.
ALTER TABLE demo_narratives ADD COLUMN IF NOT EXISTS status TEXT;                                   -- active | deprecated. Deprecated narratives are preserved for historical context but should not be used for new demos.
ALTER TABLE demo_narratives ADD COLUMN IF NOT EXISTS superseded_by TEXT;                            -- NarrativeName that replaces this one, when Status=deprecated.
COMMENT ON TABLE demo_narratives IS 'Curated narratives that demonstrate ERB capabilities in motion: substrates ''follow along'' as the rulebook changes. Two narrative styles coexist: (1) commit-sequence narratives (legacy) where a single demo rulebook evolves over commits; (2) cross-rulebook narratives (current) where the same demo is observed across DIFFERENT rulebooks side-by-side. Cross-rulebook supersedes commit-sequence because RulebookDomains now form a tree (ParentDomainId) — the progression is data, not git history.';
COMMENT ON COLUMN demo_narratives."order" IS 'Order within the narrative sequence.';
COMMENT ON COLUMN demo_narratives.narrative_name IS 'Name of the overall narrative this step belongs to.';
COMMENT ON COLUMN demo_narratives.related_domain_id IS 'FK to RulebookDomains.DomainId, when this step uses a specific demo rulebook.';
COMMENT ON COLUMN demo_narratives.observed_cost IS 'Per-substrate cost observation (e.g. ''OWL 10s, English 5min'').';
COMMENT ON COLUMN demo_narratives.narrative_style IS 'commit-sequence (legacy) | cross-rulebook (current) — how the steps are realized at demo time.';
COMMENT ON COLUMN demo_narratives.status IS 'active | deprecated. Deprecated narratives are preserved for historical context but should not be used for new demos.';
COMMENT ON COLUMN demo_narratives.superseded_by IS 'NarrativeName that replaces this one, when Status=deprecated.';

-- ----------------------------------------------------------------------------
-- Glossary: Authoritative glossary for the ERB platform. Every term used in orchestration code, docs, the admin portal UI, or rulebook tables appears here EXACTLY ONCE, with a definition AND an ImplementedAs pointer back into this rulebook (or to source files when the implementation is code rather than data). If a term appears in repo prose but has no row here, that's a documentation bug. If a term has a row here but no ImplementedAs target, that's an architecture bug — every concept should be data, code, or a value.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS glossary (
  term_id                             TEXT                 PRIMARY KEY
);
ALTER TABLE glossary ADD COLUMN IF NOT EXISTS term TEXT;                                            -- The canonical word/phrase as it appears in code and docs.
ALTER TABLE glossary ADD COLUMN IF NOT EXISTS category TEXT;                                        -- concept | role | artifact | phase | substrate | dimension | pattern | tool | location | invariant — what KIND of thing this term refers to.
ALTER TABLE glossary ADD COLUMN IF NOT EXISTS definition TEXT;                                      -- One precise sentence. Do not restate the term itself.
ALTER TABLE glossary ADD COLUMN IF NOT EXISTS implemented_as TEXT;                                  -- Pointer to where this term is realized: 'table:X', 'column:X.Y', 'value:X.Y=Z', 'file:path/to/file', or 'axiom:axiom-id'. The promise is that a reader can follow this pointer and find the concept's actual realization.
ALTER TABLE glossary ADD COLUMN IF NOT EXISTS aliases TEXT;                                         -- Comma-separated other names that should resolve to this term. The canonical spelling is in Term; aliases redirect to it.
ALTER TABLE glossary ADD COLUMN IF NOT EXISTS notes TEXT;
COMMENT ON TABLE glossary IS 'Authoritative glossary for the ERB platform. Every term used in orchestration code, docs, the admin portal UI, or rulebook tables appears here EXACTLY ONCE, with a definition AND an ImplementedAs pointer back into this rulebook (or to source files when the implementation is code rather than data). If a term appears in repo prose but has no row here, that''s a documentation bug. If a term has a row here but no ImplementedAs target, that''s an architecture bug — every concept should be data, code, or a value.';
COMMENT ON COLUMN glossary.term IS 'The canonical word/phrase as it appears in code and docs.';
COMMENT ON COLUMN glossary.category IS 'concept | role | artifact | phase | substrate | dimension | pattern | tool | location | invariant — what KIND of thing this term refers to.';
COMMENT ON COLUMN glossary.definition IS 'One precise sentence. Do not restate the term itself.';
COMMENT ON COLUMN glossary.implemented_as IS 'Pointer to where this term is realized: ''table:X'', ''column:X.Y'', ''value:X.Y=Z'', ''file:path/to/file'', or ''axiom:axiom-id''. The promise is that a reader can follow this pointer and find the concept''s actual realization.';
COMMENT ON COLUMN glossary.aliases IS 'Comma-separated other names that should resolve to this term. The canonical spelling is in Term; aliases redirect to it.';

-- ----------------------------------------------------------------------------
-- RulebookTags: Tag catalog for RulebookFlavors. Each tag has a color and emoji so it renders as a visible chip in the portal. Tags are flexible attributes — a flavor can have many tags. Browse/filter the flavors grid by any combination of tags.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS rulebook_tags (
  tag_id                              TEXT                 PRIMARY KEY          -- Stable slug identifier, e.g. tag-postgres, tag-tutorial.
);
ALTER TABLE rulebook_tags ADD COLUMN IF NOT EXISTS label TEXT;                                      -- Short human-readable label shown as the chip text.
ALTER TABLE rulebook_tags ADD COLUMN IF NOT EXISTS category TEXT;                                   -- source | substrate | purpose | complexity | feature | flavor — groups tags in the filter panel.
ALTER TABLE rulebook_tags ADD COLUMN IF NOT EXISTS color TEXT;                                      -- Hex color for the chip background, e.g. #18BFFF.
ALTER TABLE rulebook_tags ADD COLUMN IF NOT EXISTS emoji TEXT;                                      -- Emoji or icon character shown as the leading icon on the chip.
ALTER TABLE rulebook_tags ADD COLUMN IF NOT EXISTS description TEXT;                                -- One sentence: what this tag means and when to apply it.
COMMENT ON TABLE rulebook_tags IS 'Tag catalog for RulebookFlavors. Each tag has a color and emoji so it renders as a visible chip in the portal. Tags are flexible attributes — a flavor can have many tags. Browse/filter the flavors grid by any combination of tags.';
COMMENT ON COLUMN rulebook_tags.tag_id IS 'Stable slug identifier, e.g. tag-postgres, tag-tutorial.';
COMMENT ON COLUMN rulebook_tags.label IS 'Short human-readable label shown as the chip text.';
COMMENT ON COLUMN rulebook_tags.category IS 'source | substrate | purpose | complexity | feature | flavor — groups tags in the filter panel.';
COMMENT ON COLUMN rulebook_tags.color IS 'Hex color for the chip background, e.g. #18BFFF.';
COMMENT ON COLUMN rulebook_tags.emoji IS 'Emoji or icon character shown as the leading icon on the chip.';
COMMENT ON COLUMN rulebook_tags.description IS 'One sentence: what this tag means and when to apply it.';

-- ----------------------------------------------------------------------------
-- FlavorTags: Junction table linking RulebookFlavors to RulebookTags (many-to-many via junction). A flavor can have any number of tags; a tag can apply to any number of flavors. The portal renders each flavor's tags as colored chip rows in the grid and uses them to drive the filter panel.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS flavor_tags (
  flavor_tag_id                       TEXT                 PRIMARY KEY          -- Stable unique ID for this flavor↔tag assignment.
);
ALTER TABLE flavor_tags ADD COLUMN IF NOT EXISTS flavor TEXT;                                       -- FK to RulebookFlavors.FlavorId.
ALTER TABLE flavor_tags ADD COLUMN IF NOT EXISTS tag TEXT;                                          -- FK to RulebookTags.TagId.
COMMENT ON TABLE flavor_tags IS 'Junction table linking RulebookFlavors to RulebookTags (many-to-many via junction). A flavor can have any number of tags; a tag can apply to any number of flavors. The portal renders each flavor''s tags as colored chip rows in the grid and uses them to drive the filter panel.';
COMMENT ON COLUMN flavor_tags.flavor_tag_id IS 'Stable unique ID for this flavor↔tag assignment.';
COMMENT ON COLUMN flavor_tags.flavor IS 'FK to RulebookFlavors.FlavorId.';
COMMENT ON COLUMN flavor_tags.tag IS 'FK to RulebookTags.TagId.';

-- ----------------------------------------------------------------------------
-- ClaudeSkills: The catalog of Claude Code skills that make up the effortless-claude skill set. Each skill is a loadable instruction set that pre-teaches Claude everything it needs to work in an ERB project — naming conventions, pipeline mechanics, formula semantics, etc. Skills are the answer to the LLM learning-curve problem: instead of every user teaching Claude from scratch, the learning is encoded once and loaded on demand. LocalMirrorPath is a derived artifact: clone-skills.sh pulls a live copy of each skill from the source repo so the docs/skills/ mirror stays current.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS claude_skills (
  skill_id                            TEXT                 PRIMARY KEY          -- Stable PK, e.g. skill-001
);
ALTER TABLE claude_skills ADD COLUMN IF NOT EXISTS name TEXT;                                       -- Skill directory name, matches the slash command without the leading /
ALTER TABLE claude_skills ADD COLUMN IF NOT EXISTS category TEXT;                                   -- theory | modeling | pipeline | setup | tooling | data | ecosystem | features
ALTER TABLE claude_skills ADD COLUMN IF NOT EXISTS one_line_summary TEXT;                           -- One sentence describing when to use this skill
ALTER TABLE claude_skills ADD COLUMN IF NOT EXISTS audience TEXT;                                   -- customer | general — who this skill is written for
ALTER TABLE claude_skills ADD COLUMN IF NOT EXISTS clone_url TEXT;                                  -- Raw GitHub URL from which clone-skills.sh pulls a fresh copy of this skill
ALTER TABLE claude_skills ADD COLUMN IF NOT EXISTS highlight_in_readme BOOLEAN;                     -- True if this skill should appear in the README skills highlights table — the ones most directly relevant to building with this repo
COMMENT ON TABLE claude_skills IS 'The catalog of Claude Code skills that make up the effortless-claude skill set. Each skill is a loadable instruction set that pre-teaches Claude everything it needs to work in an ERB project — naming conventions, pipeline mechanics, formula semantics, etc. Skills are the answer to the LLM learning-curve problem: instead of every user teaching Claude from scratch, the learning is encoded once and loaded on demand. LocalMirrorPath is a derived artifact: clone-skills.sh pulls a live copy of each skill from the source repo so the docs/skills/ mirror stays current.';
COMMENT ON COLUMN claude_skills.skill_id IS 'Stable PK, e.g. skill-001';
COMMENT ON COLUMN claude_skills.name IS 'Skill directory name, matches the slash command without the leading /';
COMMENT ON COLUMN claude_skills.category IS 'theory | modeling | pipeline | setup | tooling | data | ecosystem | features';
COMMENT ON COLUMN claude_skills.one_line_summary IS 'One sentence describing when to use this skill';
COMMENT ON COLUMN claude_skills.audience IS 'customer | general — who this skill is written for';
COMMENT ON COLUMN claude_skills.clone_url IS 'Raw GitHub URL from which clone-skills.sh pulls a fresh copy of this skill';
COMMENT ON COLUMN claude_skills.highlight_in_readme IS 'True if this skill should appear in the README skills highlights table — the ones most directly relevant to building with this repo';

